sql:
SELECT eval_id, iter, evals
FROM evaluations
WHERE dataset_id = 1 AND algorithm_id = 1;

external_knowledge:
algorithms' identities: names of algorithms; 
algorithms' purposes: descriptions of algorithms; 
the number of trials they have undergone: evaluation_count, which refers to the total number of evaluations (trials) each algorithm has been through; 
average performance scores: average_fitness, which represents the average fitness value of the evaluations for each algorithm. This is a measure of how well an algorithm performs on average.

sql:
SELECT eval_id, iter, evals, sigma, fitness, fighter, cube, dg_min, dg_ave, dc_ave, credit, created_at, updated_at
FROM evaluations
ORDER BY created_at ASC;

SELECT eval_id, algorithm_id
FROM evaluations
WHERE algorithm_id = 1 AND evaluation_status = 'completed';

SELECT eval_id, fitness, created_at
FROM evaluations
WHERE fitness > (SELECT setting_value FROM settings WHERE setting_name = 'Default Sigma');

SELECT *
FROM evaluations
ORDER BY updated_at DESC;

SELECT * FROM evaluations
ORDER BY fitness DESC
LIMIT 3;
